// src/pages/students/StudentsList.js
import React, { useEffect, useState } from "react";
import Dashboard from "../dashboard/Dashboard";
import API from "../../api/axiosConfig";

function StudentsList() {
    const [students, setStudents] = useState([]);
    const [student, setStudent] = useState({ name: "", email: "", city: "" });
    const [editingId, setEditingId] = useState(null);
    const [loading, setLoading] = useState(false); // for async actions

    // Load students on component mount
    useEffect(() => {
        loadStudents();
    }, []);

    const loadStudents = async () => {
        setLoading(true);
        try {
            const res = await API.get("/students");
            setStudents(res.data);
        } catch (err) {
            console.error(err);
            alert("Failed to load students");
        } finally {
            setLoading(false);
        }
    };

    const handleChange = (e) => {
        setStudent({ ...student, [e.target.name]: e.target.value });
    };

    const validateStudent = () => {
        if (!student.name.trim() || !student.email.trim() || !student.city.trim()) {
            alert("All fields are required");
            return false;
        }
        return true;
    };

    const addStudent = async () => {
        if (!validateStudent()) return;
        setLoading(true);
        try {
            await API.post("/students", student);
            setStudent({ name: "", email: "", city: "" });
            loadStudents();
        } catch (err) {
            console.error(err);
            alert("Failed to add student");
        } finally {
            setLoading(false);
        }
    };

    const editStudent = (s) => {
        setStudent(s);
        setEditingId(s.id);
    };

    const updateStudent = async () => {
        if (!validateStudent()) return;
        setLoading(true);
        try {
            await API.put(`/students/${editingId}`, student);
            setStudent({ name: "", email: "", city: "" });
            setEditingId(null);
            loadStudents();
        } catch (err) {
            console.error(err);
            alert("Failed to update student");
        } finally {
            setLoading(false);
        }
    };

    const deleteStudent = async (id) => {
        if (!window.confirm("Are you sure to delete this student?")) return;
        setLoading(true);
        try {
            await API.delete(`/students/${id}`);
            alert("Student deleted successfully");
            loadStudents();
        } catch (err) {
            console.error(err);
            if (err.response && err.response.status === 403) {
                alert("Cannot delete student because it is used in enrollment");
            } else {
                alert("Delete failed");
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container mt-4">
            <div style={{ width: "100%", transform: "scale(0.6)", transformOrigin: "top" }}>
                <Dashboard />
            </div>

            <h2>Students Management</h2>

            {/* Form */}
            <div className="card p-3 mb-4">
                <input
                    type="text"
                    className="form-control mb-2"
                    placeholder="Name"
                    name="name"
                    value={student.name}
                    onChange={handleChange}
                    disabled={loading}
                />
                <input
                    type="email"
                    className="form-control mb-2"
                    placeholder="Email"
                    name="email"
                    value={student.email}
                    onChange={handleChange}
                    disabled={loading}
                />
                <input
                    type="text"
                    className="form-control mb-2"
                    placeholder="City"
                    name="city"
                    value={student.city}
                    onChange={handleChange}
                    disabled={loading}
                />

                {editingId ? (
                    <button className="btn btn-warning" onClick={updateStudent} disabled={loading}>
                        {loading ? "Updating..." : "Update Student"}
                    </button>
                ) : (
                    <button className="btn btn-primary" onClick={addStudent} disabled={loading}>
                        {loading ? "Adding..." : "Add Student"}
                    </button>
                )}
            </div>

            {/* Students Table */}
            {loading && <p>Loading...</p>}

            <table className="table table-bordered">
                <thead className="table-dark">
                <tr>
                    <th>ID</th>
                    <th>Name</th>
                    <th>Email</th>
                    <th>City</th>
                    <th>Actions</th>
                </tr>
                </thead>

                <tbody>
                {students.map((s) => (
                    <tr key={s.id}>
                        <td>{s.id}</td>
                        <td>{s.name}</td>
                        <td>{s.email}</td>
                        <td>{s.city}</td>
                        <td>
                            <button className="btn btn-sm btn-warning me-2" onClick={() => editStudent(s)} disabled={loading}>
                                Edit
                            </button>
                            <button className="btn btn-sm btn-danger" onClick={() => deleteStudent(s.id)} disabled={loading}>
                                Delete
                            </button>
                        </td>
                    </tr>
                ))}
                </tbody>
            </table>
        </div>
    );
}

export default StudentsList;