import React, { useEffect, useState } from "react";
import Dashboard from "../dashboard/Dashboard";
import API from "../../api/axiosConfig";

function EnrollmentList() {

    const [enrollments, setEnrollments] = useState([]);

    const [enrollment, setEnrollment] = useState({
        studentId: "",
        courseId: "",
        marks: ""
    });

    const [students, setStudents] = useState([]);
    const [courses, setCourses] = useState([]);

    const [editingId, setEditingId] = useState(null);

    // const API = "http://localhost:8080/enrollments";

    const token = localStorage.getItem("token");

    const authHeader = {
        headers: {
            Authorization: `Bearer ${token}`
        }
    };

    // ✅ FIXED useEffect (no dependency warning)
    useEffect(() => {

        const token = localStorage.getItem("token");

        const authHeader = {
            headers: {
                Authorization: `Bearer ${token}`
            }
        };

        const loadEnrollments = () => {
            API.get("/enrollments", authHeader)
                .then(res => setEnrollments(res.data))
                .catch(err => console.error(err));
        };

        const loadStudents = () => {
            API.get("/students", authHeader)
                .then(res => setStudents(res.data))
                .catch(err => console.error(err));
        };

        const loadCourses = () => {
            API.get("/courses", authHeader)
                .then(res => setCourses(res.data))
                .catch(err => console.error(err));
        };

        loadEnrollments();
        loadStudents();
        loadCourses();

    }, []);

    // FORM CHANGE
    const handleChange = (e) => {

        setEnrollment({
            ...enrollment,
            [e.target.name]: e.target.value
        });

    };

    // ADD ENROLLMENT
    const addEnrollment = () => {

        API.post("/enrollments", enrollment, authHeader)
            .then(() => {

                API.get("/enrollments", authHeader)
                    .then(res => setEnrollments(res.data));

                setEnrollment({
                    studentId: "",
                    courseId: "",
                    marks: ""
                });

            })
            .catch(err => console.error("Add Error:", err));

    };

    // EDIT ENROLLMENT
    const editEnrollment = (e) => {

        setEnrollment({
            studentId: e.studentId || "",
            courseId: e.courseId || "",
            marks: e.marks || ""
        });

        setEditingId(e.id);

    };

    // UPDATE ENROLLMENT
    const updateEnrollment = () => {

        API.put(`/enrollments/${editingId}`, enrollment, authHeader)
            .then(() => {

                API.get("/enrollments", authHeader)
                    .then(res => setEnrollments(res.data));

                setEnrollment({
                    studentId: "",
                    courseId: "",
                    marks: ""
                });

                setEditingId(null);

            })
            .catch(err => console.error("Update Error:", err));

    };

    // DELETE ENROLLMENT
    const deleteEnrollment = (id) => {

        if (!window.confirm("Delete this enrollment?"))
            return;

        API.delete(`/enrollments/${id}`, authHeader)
            .then(() => {

                API.get("/enrollments", authHeader)
                    .then(res => setEnrollments(res.data));

            })
            .catch(err => console.error("Delete Error:", err));

    };

    return (

        <div className="container mt-4">

            <div style={{width:"100%", transform:"scale(0.6)", transformOrigin:"top"}}>
                <Dashboard />
            </div>

            <h2>Enrollment Management</h2>

            <div className="card p-3 mb-4">

                <select
                    className="form-control mb-2"
                    name="studentId"
                    value={enrollment.studentId}
                    onChange={handleChange}
                >
                    <option value="">Select Student</option>

                    {students.map(s => (
                        <option key={s.id} value={s.id}>
                            {s.name}
                        </option>
                    ))}

                </select>

                <select
                    className="form-control mb-2"
                    name="courseId"
                    value={enrollment.courseId}
                    onChange={handleChange}
                >
                    <option value="">Select Course</option>

                    {courses.map(c => (
                        <option key={c.id} value={c.id}>
                            {c.courseName}
                        </option>
                    ))}

                </select>

                <input
                    className="form-control mb-2"
                    name="marks"
                    placeholder="Marks"
                    value={enrollment.marks}
                    onChange={handleChange}
                />

                {editingId ? (

                    <button
                        className="btn btn-warning"
                        onClick={updateEnrollment}
                    >
                        Update Enrollment
                    </button>

                ) : (

                    <button
                        className="btn btn-primary"
                        onClick={addEnrollment}
                    >
                        Add Enrollment
                    </button>

                )}

            </div>

            <table className="table table-bordered">

                <thead className="table-dark">

                <tr>
                    <th>ID</th>
                    <th>Student Name</th>
                    <th>Course Name</th>
                    <th>Marks</th>
                    <th>Actions</th>
                </tr>

                </thead>

                <tbody>

                {enrollments.map((e) => (

                    <tr key={e.id}>

                        <td>{e.id}</td>
                        <td>{e.studentName}</td>
                        <td>{e.courseName}</td>
                        <td>{e.marks}</td>

                        <td>

                            <button
                                className="btn btn-sm btn-warning me-2"
                                onClick={() => editEnrollment(e)}
                            >
                                Edit
                            </button>

                            <button
                                className="btn btn-sm btn-danger"
                                onClick={() => deleteEnrollment(e.id)}
                            >
                                Delete
                            </button>

                        </td>

                    </tr>

                ))}

                </tbody>

            </table>

        </div>

    );

}

export default EnrollmentList;